import{_ as i,o as a,c as n,ag as o}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Certificación vs Cumplimiento","description":"","frontmatter":{},"headers":[],"relativePath":"es/standards/fundamentals/certification-vs-compliance.md","filePath":"es/standards/fundamentals/certification-vs-compliance.md"}'),c={name:"es/standards/fundamentals/certification-vs-compliance.md"};function r(l,e,t,s,u,d){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="certificacion-vs-cumplimiento" tabindex="-1">Certificación vs Cumplimiento <a class="header-anchor" href="#certificacion-vs-cumplimiento" aria-label="Permalink to &quot;Certificación vs Cumplimiento&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La certificación y el cumplimiento son conceptos relacionados pero distintos que se utilizan para determinar si un producto o sistema cumple con una norma.</p><p>El cumplimiento significa que un producto está diseñado y construido de acuerdo con una norma.<br> La certificación significa que un tercero reconocido ha verificado ese cumplimiento mediante pruebas y evaluación.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Entender la diferencia es fundamental para:</p><ul><li>Asegurar que el equipo pueda instalarse y operarse legalmente</li><li>Pasar inspecciones y aprobaciones</li><li>Evitar retrasos o retrabajos en el proyecto</li><li>Seleccionar componentes que cumplan con los requisitos del proyecto</li></ul><p>Ambos conceptos se utilizan para reducir riesgos, pero proporcionan diferentes niveles de garantía.</p><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><h3 id="cumplimiento" tabindex="-1">Cumplimiento <a class="header-anchor" href="#cumplimiento" aria-label="Permalink to &quot;Cumplimiento&quot;">​</a></h3><p>El cumplimiento es una declaración del fabricante de que un producto cumple con una norma específica.</p><p>Generalmente se basa en:</p><ul><li>Prácticas internas de diseño</li><li>Validación de ingeniería</li><li>Pruebas realizadas por el fabricante</li></ul><p>El cumplimiento no siempre requiere verificación externa.</p><h3 id="certificacion" tabindex="-1">Certificación <a class="header-anchor" href="#certificacion" aria-label="Permalink to &quot;Certificación&quot;">​</a></h3><p>La certificación implica la participación de una organización independiente que:</p><ul><li>Prueba el producto contra una norma</li><li>Verifica la construcción y el desempeño</li><li>Audita los procesos de manufactura (en algunos casos)</li><li>Autoriza el uso de una marca de certificación</li></ul><p>Ejemplos incluyen listados, etiquetados o marcados por organismos reconocidos.</p><p>La certificación proporciona evidencia documentada de que el producto cumple con la norma.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><h3 id="el-cumplimiento-se-utiliza-comunmente-en" tabindex="-1">El cumplimiento se utiliza comúnmente en: <a class="header-anchor" href="#el-cumplimiento-se-utiliza-comunmente-en" aria-label="Permalink to &quot;El cumplimiento se utiliza comúnmente en:&quot;">​</a></h3><ul><li>Especificaciones internas de ingeniería</li><li>Entornos no regulados</li><li>Etapas tempranas de diseño</li><li>Sistemas personalizados sin certificación obligatoria</li></ul><h3 id="la-certificacion-generalmente-es-requerida-en" tabindex="-1">La certificación generalmente es requerida en: <a class="header-anchor" href="#la-certificacion-generalmente-es-requerida-en" aria-label="Permalink to &quot;La certificación generalmente es requerida en:&quot;">​</a></h3><ul><li>Tableros de control y equipos industriales</li><li>Dispositivos de protección eléctrica</li><li>Equipos sujetos a inspección o aprobación por autoridad</li><li>Instalaciones reguladas por normativas locales</li></ul><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><ul><li>La certificación suele ser requerida por las autoridades, no solo recomendada</li><li>Un producto que cumple puede ser rechazado si no está certificado</li><li>El alcance de la certificación es importante (componente vs sistema completo)</li><li>Diferentes regiones requieren distintos organismos de certificación</li><li>La documentación y el marcado deben coincidir con la norma utilizada</li></ul><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>No asumas que el cumplimiento es suficiente para la aprobación de instalación</li><li>Verifica los requisitos de certificación desde etapas tempranas del proyecto</li><li>Busca marcas oficiales de certificación en los equipos</li><li>En ensamblajes personalizados (ej. tableros), la certificación puede aplicar al sistema completo, no solo a los componentes</li><li>La falta de certificación es una causa común de inspecciones fallidas</li></ul>',28)])])}const f=i(c,[["render",r]]);export{m as __pageData,f as default};
